UPDATE gen_table_column c
INNER JOIN gen_table t ON t.table_id = c.table_id
SET c.is_required = CASE c.column_name

    WHEN #{column.columnName} THEN #{column.required}

    ELSE c.is_required
END,
c.update_time = NOW()
WHERE


        t.table_id = #{tableId}


        t.table_name = #{tableName}


  AND c.column_name IN

    #{column.columnName}
